import React, { Component } from 'react';
import '../Login.css';
import { default as User } from '../features/login/User';
export class Login extends Component {

  constructor(props) {
    super(props);
    this.state = { email:'', password:'', data:[], isLoading: true };
    this.handleChange = this.handleChange.bind(this);
  }

  handleSubmit = (e) => {
    const data = { email:this.state.email, password:this.state.password };
    fetch('api/customer/login',{method: 'POST', headers: {'Accept': 'application/json', 'Content-Type': 'application/json'}, body: JSON.stringify(data)})
      .then(response => response.json())
      .then(data => {
        this.setState({ data: data, isLoading: false });
        console.log(data);
 
        if(data.result === "success") {
          User.setUserLogin('true');
          console.log(User.isLogin());          
          this.props.history.push('/');
        }
        else {
          alert(data.message);
        }
      }) 
      .catch(error => this.setState({ error, isLoading: false }));
    e.preventDefault();
  }

  handleChange(e){
    this.setState({ [e.target.name]:e.target.value })
  }

  bindClick(target){
    alert(target);
  }

  render() {
    return (
      <div className="text-center">
        <h1>Kakao Login</h1>
        <a href="/api/kakao/login"><img src="//k.kakaocdn.net/14/dn/btqCn0WEmI3/nijroPfbpCa4at5EIsjyf0/o.jpg" alt="login" width="222"></img></a>

      </div>
    );
  }
}

